import io.flutter.embedding.android.FlutterFragmentActivity
import io.flutter.embedding.engine.FlutterEngine
import io.flutter.plugins.GeneratedPluginRegistrant

class MainActivity : FlutterFragmentActivity() {
    override fun configureFlutterEngine(flutterEngine: FlutterEngine) {
        GeneratedPluginRegistrant.registerWith(flutterEngine)
    }
}

I was having this issue, the above didn't fix my issue. What did was marking the original SharedPreferences variable as late

```dart
class _OptsState extends State<Opts> {
  late SharedPreferences? prefs; // Originally wasn't marked as late
  bool timings = false;

  @override
  void initState() {
    super.initState();
    _loadPreferences();
  }

  Future<void> _loadPreferences() async {
    prefs = await SharedPreferences.getInstance();
    setState(() {
      timings = prefs!.getBool('timings') ?? false;
    });
  }
}
```

